import{_ as t,o as s,c as n,ae as e}from"./chunks/framework.BdQd5MxT.js";const g=JSON.parse('{"title":"OpenAI: Agent-first Engineering Practices","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/openai-agent-engineering.md","filePath":"bestpractice/openai-agent-engineering.md"}'),i={name:"bestpractice/openai-agent-engineering.md"};function l(o,a,r,p,d,h){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="openai-agent-first-engineering-practices" tabindex="-1">OpenAI: Agent-first Engineering Practices <a class="header-anchor" href="#openai-agent-first-engineering-practices" aria-label="Permalink to &quot;OpenAI: Agent-first Engineering Practices&quot;">​</a></h1><blockquote><p>来源: <a href="https://openai.com/engineering/" target="_blank" rel="noreferrer">OpenAI Engineering Blog</a> + <a href="https://developers.openai.com/blog/" target="_blank" rel="noreferrer">Developers Blog</a> 日期: 2026-02 ~ 2026-03 分析: GSD</p></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>OpenAI 通过极端实验（5个月、100万行代码、0人工编写）验证了 <strong>Agent-first 软件开发</strong> 的可行性，核心洞察：<strong>Humans steer. Agents execute.</strong></p><hr><h2 id="核心实验-harness-engineering" tabindex="-1">核心实验：Harness Engineering <a class="header-anchor" href="#核心实验-harness-engineering" aria-label="Permalink to &quot;核心实验：Harness Engineering&quot;">​</a></h2><h3 id="极端约束实验" tabindex="-1">极端约束实验 <a class="header-anchor" href="#极端约束实验" aria-label="Permalink to &quot;极端约束实验&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>时间</td><td>5 个月</td></tr><tr><td>团队</td><td>3 人 → 7 人</td></tr><tr><td>代码产出</td><td>~100 万行</td></tr><tr><td>PR 数量</td><td>1500+</td></tr><tr><td>人工编写</td><td><strong>0 行</strong></td></tr><tr><td>效率提升</td><td><strong>~10 倍</strong></td></tr><tr><td>人均日 PR</td><td>3.5 个（随团队扩大而增加）</td></tr></tbody></table><h3 id="人类的新角色" tabindex="-1">人类的新角色 <a class="header-anchor" href="#人类的新角色" aria-label="Permalink to &quot;人类的新角色&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统工程              Agent-first 工程</span></span>
<span class="line"><span>─────────────────    ─────────────────────</span></span>
<span class="line"><span>人类写代码     →     人类设计环境、指定意图</span></span>
<span class="line"><span>代码审查       →     Agent-to-agent 审查</span></span>
<span class="line"><span>调试代码       →     调试 Agent 的能力边界</span></span>
<span class="line"><span>瓶颈：编码速度  →     瓶颈：环境 underspecified</span></span></code></pre></div><blockquote><p>&quot;Humans steer. Agents execute.&quot;</p></blockquote><hr><h2 id="agents-md-的演进" tabindex="-1">AGENTS.md 的演进 <a class="header-anchor" href="#agents-md-的演进" aria-label="Permalink to &quot;AGENTS.md 的演进&quot;">​</a></h2><h3 id="失败模式-早期" tabindex="-1">失败模式（早期） <a class="header-anchor" href="#失败模式-早期" aria-label="Permalink to &quot;失败模式（早期）&quot;">​</a></h3><ul><li>一个巨大的 AGENTS.md 文件（百科全书式）</li><li>Context 是稀缺资源 → 大文件挤占任务空间</li><li>&quot;所有事都重要&quot; = 没有事重要</li><li>文件迅速腐烂，难以验证</li></ul><h3 id="成功模式-现在" tabindex="-1">成功模式（现在） <a class="header-anchor" href="#成功模式-现在" aria-label="Permalink to &quot;成功模式（现在）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AGENTS.md (~100 行) → 目录/地图</span></span>
<span class="line"><span>├── docs/design/      → 设计文档（带验证状态）</span></span>
<span class="line"><span>├── docs/architecture/ → 架构分层说明</span></span>
<span class="line"><span>├── docs/quality/     → 各域质量评分</span></span>
<span class="line"><span>├── plans/            → 执行计划（版本化）</span></span>
<span class="line"><span>└── AGENTS.md         → 指针，指向以上各处</span></span></code></pre></div><p><strong>核心原则：Progressive Disclosure</strong></p><ul><li>Agent 从小的、稳定的入口点开始</li><li>被教导去哪里找下一步信息</li><li>而不是一开始就 overwhelm</li></ul><hr><h2 id="架构约束-为-agent-设计的严格边界" tabindex="-1">架构约束：为 Agent 设计的严格边界 <a class="header-anchor" href="#架构约束-为-agent-设计的严格边界" aria-label="Permalink to &quot;架构约束：为 Agent 设计的严格边界&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务域分层（严格单向依赖）：</span></span>
<span class="line"><span>Types → Config → Repo → Service → Runtime → UI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>跨域依赖：只能通过 Providers 接口</span></span>
<span class="line"><span></span></span>
<span class="line"><span>强制执行：</span></span>
<span class="line"><span>- 自定义 linter（Codex 生成）</span></span>
<span class="line"><span>- 结构测试</span></span>
<span class="line"><span>- 依赖方向验证</span></span></code></pre></div><p><strong>为什么需要严格架构？</strong></p><ul><li>Agent 在<strong>严格边界和可预测结构</strong>的环境中效果最好</li><li>约束 = 速度而不腐烂</li><li>通常几百人才需要的设计，Agent 时代早期就需要</li></ul><hr><h2 id="skills-shell-compaction-三件套" tabindex="-1">Skills + Shell + Compaction 三件套 <a class="header-anchor" href="#skills-shell-compaction-三件套" aria-label="Permalink to &quot;Skills + Shell + Compaction 三件套&quot;">​</a></h2><h3 id="skills-按需加载的-程序" tabindex="-1">Skills：按需加载的&quot;程序&quot; <a class="header-anchor" href="#skills-按需加载的-程序" aria-label="Permalink to &quot;Skills：按需加载的&quot;程序&quot;&quot;">​</a></h3><p><strong>定义</strong>：versioned playbook，包含文件 + SKILL.md manifest</p><p><strong>核心设计</strong>：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">setup-demo-app</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  Use when: 需要快速创建 Vite+React+Tailwind demo</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  Don&#39;t use when: 已有项目需要添加 Tailwind</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  输出: 可运行的最小项目结构</span></span></code></pre></div><p><strong>关键洞察</strong>：</p><ul><li>Skill 描述 = 模型的<strong>路由逻辑</strong>（不是营销文案）</li><li>必须回答：何时用？何时不用？输出什么？</li><li><strong>负面例子</strong>减少误触发（Glean：触发率从 -20% → 恢复）</li></ul><h3 id="shell-agent-的-执行-环境" tabindex="-1">Shell：Agent 的&quot;执行&quot;环境 <a class="header-anchor" href="#shell-agent-的-执行-环境" aria-label="Permalink to &quot;Shell：Agent 的&quot;执行&quot;环境&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>场景</th></tr></thead><tbody><tr><td>Hosted（OpenAI 托管）</td><td>可重复、隔离、部署一致</td></tr><tr><td>Local（自托管）</td><td>快速迭代、内部工具访问、易调试</td></tr></tbody></table><p><strong>开发循环</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Start local → Move to hosted when ready</span></span>
<span class="line"><span>Skills 保持不变（工作流稳定，执行环境可变）</span></span></code></pre></div><h3 id="compaction-长运行的连续性" tabindex="-1">Compaction：长运行的连续性 <a class="header-anchor" href="#compaction-长运行的连续性" aria-label="Permalink to &quot;Compaction：长运行的连续性&quot;">​</a></h3><p><strong>问题</strong>：长工作流遇到 context window 限制</p><p><strong>解法</strong>：</p><ul><li><strong>Server-side compaction</strong>：自动在流中压缩</li><li><strong>Standalone compact endpoint</strong>：显式控制时机</li></ul><p><strong>设计原则</strong>：</p><ul><li>为长运行早期就设计连续性</li><li>复用同一容器（稳定依赖、缓存文件）</li><li>传递 previous_response_id</li><li>将 compaction 作为<strong>默认原语</strong>，而非紧急 fallback</li></ul><hr><h2 id="skill-eval-方法论" tabindex="-1">Skill Eval 方法论 <a class="header-anchor" href="#skill-eval-方法论" aria-label="Permalink to &quot;Skill Eval 方法论&quot;">​</a></h2><h3 id="eval-是什么" tabindex="-1">Eval 是什么？ <a class="header-anchor" href="#eval-是什么" aria-label="Permalink to &quot;Eval 是什么？&quot;">​</a></h3><blockquote><p>&quot;Prompt → Captured run (trace + artifacts) → Checks → Score&quot;</p></blockquote><p><strong>替代&quot;感觉更好&quot;（vibes）→ 可量化的证明</strong></p><h3 id="成功定义的四个维度" tabindex="-1">成功定义的四个维度 <a class="header-anchor" href="#成功定义的四个维度" aria-label="Permalink to &quot;成功定义的四个维度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>问题</th></tr></thead><tbody><tr><td>Outcome goals</td><td>任务完成了吗？App 能运行吗？</td></tr><tr><td>Process goals</td><td>调用了预期的 skill 和步骤吗？</td></tr><tr><td>Style goals</td><td>输出符合约定的规范吗？</td></tr><tr><td>Efficiency goals</td><td>有没有 thrashing？</td></tr></tbody></table><h3 id="轻量级-eval-流程" tabindex="-1">轻量级 Eval 流程 <a class="header-anchor" href="#轻量级-eval-流程" aria-label="Permalink to &quot;轻量级 Eval 流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 创建 prompts.csv（10-20 条）</span></span>
<span class="line"><span>   - 显式调用 / 隐式触发 / 带噪声场景 / 负面控制</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 运行 codex exec --json → 捕获 JSONL trace</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 确定性检查</span></span>
<span class="line"><span>   - 是否运行了 npm install？</span></span>
<span class="line"><span>   - 是否创建了 package.json？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 模型辅助评分（Rubric-based）</span></span>
<span class="line"><span>   - 评分维度：vite, tailwind, structure, style</span></span>
<span class="line"><span>   - 返回：overall_pass, score, checks[]</span></span></code></pre></div><hr><h2 id="对我们的借鉴" tabindex="-1">对我们的借鉴 <a class="header-anchor" href="#对我们的借鉴" aria-label="Permalink to &quot;对我们的借鉴&quot;">​</a></h2><h3 id="立即可做" tabindex="-1">立即可做 <a class="header-anchor" href="#立即可做" aria-label="Permalink to &quot;立即可做&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>现状</th><th>改进</th></tr></thead><tbody><tr><td>AGENTS.md 过长</td><td>启动时加载全部</td><td>精简为目录，按需加载</td></tr><tr><td>无 Skill 规范</td><td>流程依赖口头约定</td><td>提取 <code>task-handoff</code> 等 Skills</td></tr><tr><td>无 Eval 意识</td><td>质量靠&quot;感觉&quot;</td><td>定义 3-5 个核心检查点</td></tr><tr><td>代码漂移</td><td>重复讨论模式</td><td>编码 Golden Principles</td></tr></tbody></table><h3 id="架构层面" tabindex="-1">架构层面 <a class="header-anchor" href="#架构层面" aria-label="Permalink to &quot;架构层面&quot;">​</a></h3><p><strong>1. AGENTS.md → 目录化</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AGENTS.md（精简版，~50 行）</span></span>
<span class="line"><span>├── docs/soul/        → 核心身份</span></span>
<span class="line"><span>├── docs/tools/       → 工具指南</span></span>
<span class="line"><span>├── docs/memory/      → 历史记录（分层）</span></span>
<span class="line"><span>│   ├── recent/       → 最近 7 天详细</span></span>
<span class="line"><span>│   └── archive/      → 归档摘要</span></span>
<span class="line"><span>└── shared/           → 跨 Agent 共享</span></span></code></pre></div><p><strong>2. Skill 化协作流程</strong></p><ul><li><code>task-handoff</code>：WLB → GSD 任务交接</li><li><code>slack-report</code>：状态更新格式</li><li><code>feishu-doc-ops</code>：飞书文档操作</li></ul><p><strong>3. Eval 化协作质量</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>方法</th></tr></thead><tbody><tr><td>任务正确交接</td><td>GSD 是否正确读取任务 JSON？</td></tr><tr><td>状态正确更新</td><td>#tasks 是否有对应消息？</td></tr><tr><td>执行符合预期</td><td>结果是否匹配任务要求？</td></tr><tr><td>效率合理</td><td>Token 使用、步骤数</td></tr></tbody></table><p><strong>4. Golden Principles 持续清理</strong></p><ul><li>将原则编码（如：所有任务必须先在 #tasks 记录）</li><li>定期扫描偏离</li><li>自动提出整理 PR</li></ul><hr><h2 id="与-anthropic-实践的对比" tabindex="-1">与 Anthropic 实践的对比 <a class="header-anchor" href="#与-anthropic-实践的对比" aria-label="Permalink to &quot;与 Anthropic 实践的对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Anthropic</th><th>OpenAI</th></tr></thead><tbody><tr><td><strong>核心关注</strong></td><td>Agent 设计、eval、harness</td><td>Agent-first 工程流程、工具生态</td></tr><tr><td><strong>Context 管理</strong></td><td>Context Engineering、Context Rot</td><td>Compaction、Progressive Disclosure</td></tr><tr><td><strong>Multi-Agent</strong></td><td>Orchestrator-Worker、Memory</td><td>Skills 路由、Agent-to-agent 审查</td></tr><tr><td><strong>评估</strong></td><td>AI-resistant eval</td><td>Skill evals、deterministic + rubric</td></tr><tr><td><strong>架构</strong></td><td>较少涉及</td><td>严格分层、机械约束</td></tr><tr><td><strong>代码生成</strong></td><td>Claude Code 最佳实践</td><td>100% Agent 生成代码的极端实验</td></tr></tbody></table><p><strong>互补性</strong>：</p><ul><li>Anthropic 提供 Agent <strong>设计方法论</strong></li><li>OpenAI 提供 Agent <strong>工程化基础设施</strong></li><li>两者结合 = 完整的 Agent 系统构建指南</li></ul><hr><h2 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h2><h3 id="_1-progressive-disclosure-是关键" tabindex="-1">1. Progressive Disclosure 是关键 <a class="header-anchor" href="#_1-progressive-disclosure-是关键" aria-label="Permalink to &quot;1. Progressive Disclosure 是关键&quot;">​</a></h3><p>不是给 Agent 所有信息，而是给<strong>入口点 + 导航图</strong>。</p><h3 id="_2-约束-速度" tabindex="-1">2. 约束 = 速度 <a class="header-anchor" href="#_2-约束-速度" aria-label="Permalink to &quot;2. 约束 = 速度&quot;">​</a></h3><p>严格架构不是限制，而是让 Agent 更高效工作的环境设计。</p><h3 id="_3-eval-是工程化的标志" tabindex="-1">3. Eval 是工程化的标志 <a class="header-anchor" href="#_3-eval-是工程化的标志" aria-label="Permalink to &quot;3. Eval 是工程化的标志&quot;">​</a></h3><p>从&quot;感觉更好&quot;到&quot;可量化证明&quot;，是 Agent 系统成熟的标志。</p><h3 id="_4-人类角色转变" tabindex="-1">4. 人类角色转变 <a class="header-anchor" href="#_4-人类角色转变" aria-label="Permalink to &quot;4. 人类角色转变&quot;">​</a></h3><p>从&quot;写代码的人&quot;变成&quot;设计环境、指定意图、构建反馈循环的人&quot;。</p><hr><h2 id="原文引用" tabindex="-1">原文引用 <a class="header-anchor" href="#原文引用" aria-label="Permalink to &quot;原文引用&quot;">​</a></h2><blockquote><p>&quot;5 months. ~1 million lines of code. 0 lines written by a human.&quot;</p></blockquote><blockquote><p>&quot;Humans steer. Agents execute.&quot;</p></blockquote><blockquote><p>&quot;Good context engineering means finding the smallest possible set of high-signal tokens that maximize the likelihood of some desired outcome.&quot;</p></blockquote><hr><p><em>下一篇: <a href="/LIP/bestpractice/anthropic-context-engineering.html">Anthropic Context Engineering 分析 →</a></em></p>`,87)])])}const u=t(i,[["render",l]]);export{g as __pageData,u as default};
